// C0684 · REST CRUD JSON (GET/POST/PUT/DELETE)
import io.micronaut.http.annotation.*;
import java.util.*;

@Controller("/items")
public class ItemsController {
  private final Map<Integer, Map<String,Object>> items = new LinkedHashMap<>();
  private int seq = 1;

  @Get public Collection<Map<String,Object>> list(){ return items.values(); }

  @Post public Map<String,Object> create(@Body Map<String,Object> body){
    var it = new LinkedHashMap<String,Object>();
    it.put("id", seq++);
    it.put("name", String.valueOf(body.getOrDefault("name","")));
    items.put((Integer)it.get("id"), it);
    return it;
  }
}

