// C0685 · Middleware logging + tiempo de respuesta
import io.micronaut.http.*;
import io.micronaut.http.filter.*;
import org.reactivestreams.Publisher;
import jakarta.inject.Singleton;

@Singleton
public class TimingFilter implements HttpServerFilter {
  @Override
  public Publisher<MutableHttpResponse<?>> doFilter(HttpRequest<?> request, ServerFilterChain chain) {
    long t0 = System.currentTimeMillis();
    return io.reactivex.Flowable.fromPublisher(chain.proceed(request))
      .doFinally(() -> System.out.println(request.getMethod() + " " + request.getPath() + " " + (System.currentTimeMillis()-t0) + "ms"));
  }
}

